.darma-loader-darma-research-sunrise-arch-progress { --speed: var(--loader-speed, 1s); --accent: var(--loader-color, #f97316); --accent-2: var(--loader-secondary-color, #facc15); width: calc(var(--loader-size, 80px) * 1.8); height: var(--loader-size, 80px); position: relative; overflow: hidden; }
.darma-loader-darma-research-sunrise-arch-progress::before { content: ""; position: absolute; left: 8%; right: 8%; bottom: 18%; height: 70%; border-radius: 999px 999px 0 0; border: 5px solid transparent; border-top-color: var(--accent); border-left-color: color-mix(in srgb, var(--accent) 35%, transparent); border-right-color: color-mix(in srgb, var(--accent-2) 35%, transparent); }
.darma-loader-darma-research-sunrise-arch-progress__sun { position: absolute; width: 22%; aspect-ratio: 1; border-radius: 50%; background: radial-gradient(circle, #fff 0 8%, var(--accent) 40%, var(--accent-2)); left: 39%; bottom: 18%; box-shadow: 0 0 22px var(--accent); transform-origin: 50% calc(var(--loader-size, 80px) * .55); animation: darma-loader-darma-research-sunrise-arch-progress-sunrise-arc calc(var(--speed) * 2.4) ease-in-out infinite; }
.darma-loader-darma-research-sunrise-arch-progress__line { position: absolute; left: 10%; right: 10%; bottom: 18%; height: 5px; border-radius: 999px; background: linear-gradient(90deg, var(--accent), var(--accent-2)); }
@keyframes darma-loader-darma-research-sunrise-arch-progress-sunrise-arc { 0% { transform: rotate(-78deg); opacity:.4; } 50% { transform: rotate(0deg); opacity:1; } 100% { transform: rotate(78deg); opacity:.4; } }

